import React from 'react';
import { BrowserRouter, Routes, Route, Navigate } from 'react-router-dom';
import { AuthProvider, useAuth } from './context/AuthContext';
import { DataProvider } from './context/DataContext';
import LoginForm from './components/LoginForm';

// Layouts
import AdminLayout from './components/Layouts/AdminLayout';
import StaffLayout from './components/Layouts/StaffLayout';
import SchedulerLayout from './components/Layouts/SchedulerLayout'; // MỚI

// Pages
import StaffManager from './pages/Admin/StaffManager';
import TaskManager from './pages/Admin/TaskManager';
import DisciplineManager from './pages/Admin/DisciplineManager';
import Reports from './pages/Admin/Reports';

import Attendance from './pages/Staff/Attendance';
import MyTasks from './pages/Staff/MyTasks';
import FacilityCheck from './pages/Staff/FacilityCheck';
import Performance from './pages/Staff/Performance';
import StaffReports from './pages/Staff/StaffReport'; // MỚI
import SchedulerTaskManager from './pages/Scheduler/SchedulerTaskManager'; // MỚI

// Protected Route Component
const PrivateRoute = ({ children, allowedRoles }) => {
  const { user } = useAuth();
  if (!user) return <Navigate to="/" />;
  if (allowedRoles && !allowedRoles.includes(user.role)) return <Navigate to="/" />;
  return children;
};

function App() {
  return (
    <AuthProvider>
      <DataProvider>
        <BrowserRouter>
          <Routes>
            <Route path="/" element={<LoginForm />} />

            {/* ADMIN ROUTES */}
            <Route path="/admin" element={<PrivateRoute allowedRoles={['chief', 'reg', 'op', 'admin']}><AdminLayout /></PrivateRoute>}>
                <Route path="staff-manager" element={<StaffManager />} />
                <Route path="tasks" element={<TaskManager />} />
                <Route path="discipline" element={<DisciplineManager />} />
                <Route path="reports" element={<Reports />} />
            </Route>

            {/* SCHEDULER ROUTES (MỚI) */}
            <Route path="/scheduler" element={<PrivateRoute allowedRoles={['scheduler']}><SchedulerLayout /></PrivateRoute>}>
                <Route path="tasks" element={<SchedulerTaskManager />} />
            </Route>

            {/* STAFF ROUTES */}
            <Route path="/staff" element={<PrivateRoute allowedRoles={['staff']}><StaffLayout /></PrivateRoute>}>
                <Route path="attendance" element={<Attendance />} />
                <Route path="tasks" element={<MyTasks />} />
                <Route path="facility" element={<FacilityCheck />} />
                <Route path="reports" element={<StaffReports />} /> {/* MỚI */}
                <Route path="performance" element={<Performance />} />
            </Route>

          </Routes>
        </BrowserRouter>
      </DataProvider>
    </AuthProvider>
  );
}

export default App;
